scwin.onUdcCompleted = function () {
  scwin.initSetting();
  if (scwin.userClsCd != "01") {
    //사용자 구분 : 05
    ed_srchSelfTransCoCd.setValue(scwin.clntNo);
    ed_srchSelfTransCoNm.setValue(scwin.clntNm);
    $c.gus.cfDisableObjects($p, [ed_srchSelfTransCoCd, ed_srchSelfTransCoNm, btn_srchSelfTransCoCd]);
    ed_odrNo.setValue(scwin.odrNo);
    ed_odrNo.focus();
  } else {
    ed_srchSelfTransCoCd.setValue(scwin.selfTransClntNo);
    ed_srchSelfTransCoNm.setValue(scwin.selfTransClntNm);
    $c.gus.cfEnableObjects($p, [ed_srchSelfTransCoCd, ed_srchSelfTransCoNm, btn_srchSelfTransCoCd]);
    ed_odrNo.setValue(scwin.odrNo);
    //ed_srchSelfTransCoCd.Focus();
  }
  if (ed_srchSelfTransCoCd.getValue() != "" && ed_srchSelfTransCoNm.getValue() != "" && ed_odrNo.getValue() != "") {
    if (!$c.gus.cfValidate($p, ed_odrNo)) {
      return;
    }
    scwin.f_Retrieve();
  }
  ;
};
scwin.initSetting = function () {
  scwin.memJson = $c.data.getMemInfo($p);
  scwin.params = $c.data.getParameter($p);
  //반입,반납승인현황 페이지 에서넘어옴 selfTransClntNo, selfTransClntNm, odrNo
  scwin.selfTransClntNo = scwin.params.selfTransClntNo == null || scwin.params.selfTransClntNo == undefined ? "" : scwin.params.selfTransClntNo;
  scwin.selfTransClntNm = scwin.params.selfTransClntNm == null || scwin.params.selfTransClntNm == undefined ? "" : scwin.params.selfTransClntNm;
  scwin.odrNo = scwin.params.odrNo == null || scwin.params.odrNo == undefined ? "" : scwin.params.odrNo;

  //세션정보

  scwin.userClsCd = scwin.memJson.userClsCd;
  //사용자구분코드(01:그룹사구분코드(01:그룹사, 02:협력업체(운송), 03:선사, 04:화주, 05:자가운송업체, 06:렌터카(고객), 07:정비(고객))

  scwin.clntNo = scwin.memJson.clntNo; //거래처번호
  scwin.clntNm = scwin.memJson.clntNm; //거래처명
  scwin.loginId = scwin.memJson.userId; //거래처ID
  if (scwin.userClsCd == null) scwin.userClsCd = "";
  scwin.strDate = WebSquare.date.getCurrentServerDate().substring(0, 6);
  scwin.nowDt = WebSquare.date.getCurrentServerDate().substring(0, 8);
};

