scwin.f_Excel = async function () {
  //var objGridName = eval("gr_total");     
  let ret = await $c.win.confirm($p, "Excel로 다운로드 하시겠습니까?");
  if (ret) {
    let colCount = 0;
    var nonColArray = new Array();
    for (let i = 0; i < gr_OnOffHireLduld.getTotalCol(); i++) {
      if (gr_OnOffHireLduld.getColumnVisible(i) == true) {
        colCount++;
      }
    }
    let infoArr = [{
      rowIndex: 0,
      colIndex: 0,
      rowSpan: 1,
      colSpan: colCount,
      text: "On Hire 상하차 내역",
      textAlign: "center",
      fontSize: 12,
      drawBorder: false,
      color: "black",
      backgroundColor: "#ffffff"
    }, {
      rowIndex: 2,
      colIndex: 0,
      rowSpan: 1,
      colSpan: colCount,
      text: "운송사 | " + ed_srchSelfTransCoNm.getValue() + "]" + " | 오더 No |" + ed_odrNo.getValue() + " | 컨테이너" + " | " + ed_cntrNo.getValue(),
      textAlign: "left",
      fontSize: 10,
      drawBorder: false,
      color: "black",
      backgroundColor: "#ffffff"
    }];
    const options = {
      fileName: "On Hire 상하차 내역.xlsx",
      // + ".xls",
      sheetName: "On Hire 상하차 내역",
      useStyle: true,
      oddRowBackgroundColor: "#CCFFCC",
      startRowIndex: 3,
      startColumnIndex: 0
    };
    await $c.data.downloadGridViewExcel($p, gr_OnOffHireLduld, options, infoArr);
  }
};
