scwin.f_Retrieve = async function () {
  let rtn = await $c.gus.cfValidate($p, [ed_odrNo]);
  if (!rtn) {
    return false;
  }
  dma_condition.set("odrNo", ed_odrNo.getValue());
  dma_condition.set("cntrNo", ed_cntrNo.getValue());
  dma_condition.set("odrCompleteYn", acb_odrCompleteYn.getValue());
  $c.sbm.execute($p, sbm_retrieve);
};

