scwin.f_Save = async function () {
  if (ds_onOffHireLduld.getModifiedIndex().length == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["On Hire 상하차 내역"]); // "@은(는) 변경된 사항이 없습니다."
    return;
  }
  if (ed_srchSelfTransCoCd.getValue() == "") {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["자가운송사"]);
    ed_srchSelfTransCoCd.focus();
    return;
  }

  // 검색조건 필수 입력 체크
  if (!$c.gus.cfValidate($p, [gr_OnOffHireLduld])) {
    return;
  }
  for (var i = 0; i <= ds_onOffHireLduld.getRowCount(); i++) {
    if (ds_onOffHireLduld.getCellData(i, "crryinoutIntendDt") != scwin.nowDt) {
      if (ds_onOffHireLduld.getCellData(i, "wrkPlCd") == "4C02") {
        $c.win.alert($p, "금일 신규 예약 하십시오.");
        return;
      }
    }
    if (ds_onOffHireLduld.getRowStatus(i) == "U") {
      if (ds_onOffHireLduld.getCellData(i, "crryinoutIntendHh").length != 4) {
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_055, ["시간형식"]);
        ds_onOffHireLduld.setRowPosition(i);
        gr_OnOffHireLduld.setFocusedCell(i, 5); //SetColumn("crryinoutIntendHh");
        //gr_OnOffHireLduld.focus();
        return false;
      }
      if (ds_onOffHireLduld.getCellData(i, "crryinoutIntendHh").substr(0, 2) > "23") {
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_021, ["반납예정시간"]); // "@은(는) 시가 잘못되었습니다."
        ds_onOffHireLduld.setRowPosition(i);
        gr_OnOffHireLduld.setFocusedCell(i, 5);
        gr_OnOffHireLduld.focus();
        return false;
      }
      if (ds_onOffHireLduld.getCellData(i, "crryinoutIntendHh").substr(2, 2) > "59") {
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["반납예정시간"]); // "@은(는) 분이 잘못되었습니다."
        ds_onOffHireLduld.setRowPosition(i);
        gr_OnOffHireLduld.setFocusedCell(i, 5);
        gr_OnOffHireLduld.focus();
        return false;
      }
      if (ds_onOffHireLduld.getCellData(i, "crryinoutIntendNo") == "") {
        ds_onOffHireLduld.setCellData(i, "selfTransCoClntNo", ed_srchSelfTransCoCd.getValue());
      }
    }
  }
  var strOdrNo = ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "odrNo");
  if (ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "TSL" && strOdrNo.substring(1, 3) == "C5") {
    alert("TSL라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
    return false;
  } else if (ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "EAS" && strOdrNo.substring(1, 3) == "C5") {
    alert("EAS라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
    return false;
  } else if (ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "APL") {
    alert("APL라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
    return false;
  } else if (ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "COH" && strOdrNo.substring(1, 3) == "C5" && $s.gus.cfIsNull(ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "bookingNo"))) {
    if (scwin.loginId == "010028") {
      let rtn = await $c.win.confirm($p, "저장 하시겠습니까?");
      if (rtn) {
        //tr_regist.Post();
      }
    } else {
      $c.win.alert($p, "COH라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
      return false;
    }
  } else if (ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "YNK") {
    if (scwin.loginId == "010028") {
      if ($c.gus.cfConfirmMsg($p, "저장 하시겠습니까?")) {
        //tr_regist.Post();
      }
    } else {
      $c.win.alert($p, "YNK라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
      return false;
    }
  } else if (ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "SITC") {
    if (scwin.loginId == "072893" || scwin.loginId == "073294" || scwin.loginId == "281776" || scwin.loginId == "010028") {
      if ($c.gus.cfConfirmMsg($p, "저장 하시겠습니까?")) {
        //tr_regist.Post();
      }
    } else {
      $c.win.alert($p, "SITC라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
      return false;
    }
  } else if (ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "NOLS" || ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "TCLC" || ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "SOFC" || ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "TMSC" || ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "TJM" || ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "MAS" || ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "JJS" || ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "DWH" || ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "RHT" || ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "ONE") {
    //두우해운 문상보 대리 요청..	, 2014.09.22 TMSC라인 추가
    if (scwin.loginId == "040300" || scwin.loginId == "001234") {
      if ($c.gus.cfConfirmMsg($p, "저장 하시겠습니까?")) {
        //tr_regist.Post();
      }
    } else {
      $c.win.alert($p, "NOLS, TCLC, SOFC, TMSC, TJM, MAS, JJS, DWH, RHT, ONE 라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
      return false;
    }
  } else if (ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "COS") {
    $c.win.alert($p, "COS라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
    return false;
  } else if (ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "lineCd") == "MOL") {
    $c.win.alert($p, "MOL라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
    return false;
  } else if (await $c.win.confirm($p, "저장 하시겠습니까?")) {
    $c.sbm.execute($p, sbm_save);
  }
};
