scwin.gr_OnOffHireLduld_oneditend = async function (rowIndex, columnIndex, value) {
  var row = rowIndex;
  if (columnIndex == 7) {
    var tempString = "";
    tempString = value;
    if (tempString.length != 9) {
      await $c.win.alert($p, "차량번호는 영업번호 9자리를 모두 입력해 주세요 \n      Ex>부산99바1234");
      ds_onOffHireLduld.setCellData(row, "vehclNo", "");
      return;
    } else {
      //가운데 숫자체크
      //alert("aa:::"+Number(ed_vehclNoFull1.Text.substring(2,4)));
      if (Number(tempString.substring(2, 4)) >= 00 && Number(tempString.substring(2, 4)) <= 99 && tempString.substring(2, 4).length == 2) {
        //alert("OK");
      } else {
        await $c.win.alert($p, "세번째 네번째는 숫자이어야 합니다. ");
        ds_onOffHireLduld.setCellData(row, "vehclNo", "");
        return;
      }
      //마지막 네자리 숫자 체트
      //alert("aa:::"+Number(ed_vehclNoFull1.Text.substring(5,10)));
      if (Number(tempString.substring(5, 10)) >= 0000 && Number(tempString.substring(5, 10)) <= 9999 && tempString.substring(5, 10).length == 4) {
        //alert("OK");
      } else {
        await $c.win.alert($p, "끝에 네자리는 숫자이어야 합니다. ");
        ds_onOffHireLduld.setCellData(row, "vehclNo", "");
        return;
      }

      //처음2자리 문자자체크

      var kk = tempString.substring(0, 2);
      if (kk == null) {
        return false;
      }
      for (var i = 0; i < kk.length; i++) {
        var c = kk.charCodeAt(i);
        if (!(0xAC00 <= c && c <= 0xD7A3 || 0x3131 <= c && c <= 0x318E)) {
          await $c.win.alert($p, "처음2자리 한글이어야 합니다.!!! ");
          ds_onOffHireLduld.setCellData(row, "vehclNo", "");
          return;
        }
      }
      //가운데1자리 문자자체크

      var kkk = tempString.substring(4, 5);
      if (kkk == null) {
        return;
      }
      for (var i = 0; i < kkk.length; i++) {
        var c = kkk.charCodeAt(i);
        if (!(0xAC00 <= c && c <= 0xD7A3 || 0x3131 <= c && c <= 0x318E)) {
          await $c.win.alert($p, "다섯번째는 한글이어야 합니다.!!! ");
          ds_onOffHireLduld.setCellData(row, "vehclNo", "");
          return;
        }
      }
    } //else         
  }
};
scwin.sbm_retrieve_submitDone = function () {
  var odrNo = ""; //오더번호
  var lineNm = ""; //LINE명
  var regiNm = ""; //담당자
  var odrDelYn = ""; //오더삭제여부
  var odrCompleteYn = ""; //오더완료여부
  var odrCompleteDt = ""; //완료일자
  if (ds_onOffHireLduld.getRowCount() == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_003);
    //		cfDisableObjects([btn_01,btn_02,btn_03]);
    $c.gus.cfDisableObjects($p, [btn_03]);
    $c.gus.cfDisableObjects($p, [btn_04]);
    odrNo = ""; //오더번호
    lineNm = ""; //LINE명
    regiNm = ""; //담당자
    odrDelYn = ""; //오더삭제여부
    odrCompleteYn = ""; //오더완료여부
    odrCompleteDt = ""; //완료일자
  } else {
    //  		cfEnableObjects([btn_01,btn_02,btn_03]);
    //cfEnableObjects([btn_03]);

    $c.gus.cfEnableObj($p, btn_03, true);
    $c.gus.cfEnableObj($p, btn_04, true);
    odrNo = ds_onOffHireLduld.getCellData(0, "odrNo");
    lineNm = ds_onOffHireLduld.getCellData(0, "lineNm");
    regiNm = ds_onOffHireLduld.getCellData(0, "regiNm");
    if (ds_onOffHireLduld.getCellData(0, "odrDelYn") == 0) {
      odrDelYn = "No";
    } else if (ds_onOffHireLduld.getCellData(0, "odrDelYn") == 1) {
      odrDelYn = "Yes";
    }
    if (ds_onOffHireLduld.getCellData(0, "odrCompleteYn") == 0) {
      odrCompleteYn = "No";
    } else if (ds_onOffHireLduld.getCellData(0, "odrCompleteYn") == 1) {
      odrCompleteYn = "Yes";
    }
    if (ds_onOffHireLduld.getCellData(1, "odrCompleteDt") != "") {
      odrCompleteDt = $c.gus.cfGetFormatStr($p, ds_onOffHireLduld.getCellData(0, "odrCompleteDt"), "####/##/##");
    }
  }
  ;
  ed_odrNo1.setValue(odrNo);
  ed_lineNm.setValue(lineNm);
  ed_regiNm.setValue(regiNm);
  ed_odrDelYn.setValue(odrDelYn);
  ed_odrCompleteYn.setValue(odrCompleteYn);
  ed_odrCompleteDt.setValue(odrCompleteDt);
  var userClsCd = scwin.userClsCd;

  //경인지역인 경우, 사용자 구분 : 01이 아닌경우(자가)에 하차증 발행버튼 보여줌
  if (ds_onOffHireLduld.getCellData(ds_onOffHireLduld.getRowPosition(), "wrkPlCd") == "4C02" && userClsCd != "01") {
    //printYn.style.display = "block";

    gr_OnOffHireLduld.setColumnVisible("chk", true);
  } else {
    //printYn.style.display = "none";
    gr_OnOffHireLduld.setColumnVisible("chk", false);
    //gr_OnOffHireLduld.ColumnProp("chk", "Show") = "False";
  }
  ;

  // 그리드 조건 처리
  for (var i = 0; i <= ds_onOffHireLduld.getRowCount(); i++) {
    if (ds_onOffHireLduld.getCellData(i, "gatelogNo") != "") {
      gr_OnOffHireLduld.setCellReadOnly(i, "crryinoutIntendDt", true);
      gr_OnOffHireLduld.setCellReadOnly(i, "crryinoutIntendHh", true);
      gr_OnOffHireLduld.setCellReadOnly(i, "vehclNo", true);
      gr_OnOffHireLduld.setCellReadOnly(i, "drvNm", true);
      gr_OnOffHireLduld.setCellReadOnly(i, "drvTelNo", true);
    } else {
      //gr_OnOffHireLduld.ColumnProp("crryinoutIntendDt", 'Edit') = "";
      //gr_OnOffHireLduld.ColumnProp("crryinoutIntendHh", 'Edit') = "";
      gr_OnOffHireLduld.setCellReadOnly(i, "sealNo", false);
      gr_OnOffHireLduld.setCellReadOnly(i, "vehclIdCardNo", false);
      gr_OnOffHireLduld.setCellReadOnly(i, "status", false);
      gr_OnOffHireLduld.setCellReadOnly(i, "vehclNo", false);
      gr_OnOffHireLduld.setCellReadOnly(i, "drvNm", false);
      gr_OnOffHireLduld.setCellReadOnly(i, "drvTelNo", false);
    }
    if (ds_onOffHireLduld.getCellData(i, "selfClsCd") != "JE") {
      gr_OnOffHireLduld.setCellReadOnly(i, "crryinoutIntendDt", true);
      gr_OnOffHireLduld.setCellReadOnly(i, "crryinoutIntendHh", true);
      gr_OnOffHireLduld.setCellReadOnly(i, "vehclNo", false);
      gr_OnOffHireLduld.setCellReadOnly(i, "drvNm", false);
      gr_OnOffHireLduld.setCellReadOnly(i, "drvTelNo", false);
    } else {
      //gr_OnOffHireLduld.ColumnProp("crryinoutIntendDt", 'Edit') = "";
      //gr_OnOffHireLduld.ColumnProp("crryinoutIntendHh", 'Edit') = "";
      gr_OnOffHireLduld.setCellReadOnly(i, "vehclNo", false);
      gr_OnOffHireLduld.setCellReadOnly(i, "drvNm", false);
      gr_OnOffHireLduld.setCellReadOnly(i, "drvTelNo", false);
      gr_OnOffHireLduld.setCellReadOnly(i, "sealNo", false);
      gr_OnOffHireLduld.setCellReadOnly(i, "vehclIdCardNo", false);
      gr_OnOffHireLduld.setCellReadOnly(i, "status", false);
    }
    ;
  }
  ;
  gr_OnOffHireLduld.setFocusedCell(0, 0);
  totalRows.setValue(ds_onOffHireLduld.getRowCount());
};
